import pygame
import random

pygame.init()

WIDTH, HEIGHT = 600, 600
CELL_SIZE = 20
GRID_WIDTH = WIDTH // CELL_SIZE
GRID_HEIGHT = HEIGHT // CELL_SIZE

WHITE = (255, 255, 255)
GREEN = (0, 200, 0)
DARK_GREEN = (0, 100, 0)
RED = (200, 0, 0)
BLACK = (0, 0, 0)

screen = pygame.display.set_mode((WIDTH, HEIGHT))
pygame.display.set_caption("贪吃蛇 - Nova游戏")
clock = pygame.time.Clock()
font = pygame.font.SysFont("Arial", 30)

class Snake:
    def __init__(self):
        self.body = [(GRID_WIDTH // 2, GRID_HEIGHT // 2)]
        self.direction = (1, 0)
        self.grow = False

    def move(self):
        head = self.body[0]
        new_head = (head[0] + self.direction[0], head[1] + self.direction[1])

        if new_head[0] < 0 or new_head[0] >= GRID_WIDTH:
            return False
        if new_head[1] < 0 or new_head[1] >= GRID_HEIGHT:
            return False
        if new_head in self.body:
            return False

        self.body.insert(0, new_head)
        if not self.grow:
            self.body.pop()
        self.grow = False
        return True

    def draw(self):
        for i, segment in enumerate(self.body):
            color = GREEN if i == 0 else DARK_GREEN
            pygame.draw.rect(screen, color, 
                           (segment[0] * CELL_SIZE, segment[1] * CELL_SIZE,
                            CELL_SIZE - 2, CELL_SIZE - 2), border_radius=5)

class Food:
    def __init__(self):
        self.pos = (random.randint(0, GRID_WIDTH - 1), 
                    random.randint(0, GRID_HEIGHT - 1))

    def draw(self):
        pygame.draw.circle(screen, RED,
                          (self.pos[0] * CELL_SIZE + CELL_SIZE // 2,
                           self.pos[1] * CELL_SIZE + CELL_SIZE // 2),
                          CELL_SIZE // 2 - 2)

def main():
    snake = Snake()
    food = Food()
    score = 0
    running = True
    game_over = False

    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.KEYDOWN:
                if game_over:
                    if event.key == pygame.K_SPACE:
                        snake = Snake()
                        food = Food()
                        score = 0
                        game_over = False
                else:
                    if event.key == pygame.K_UP and snake.direction != (0, 1):
                        snake.direction = (0, -1)
                    elif event.key == pygame.K_DOWN and snake.direction != (0, -1):
                        snake.direction = (0, 1)
                    elif event.key == pygame.K_LEFT and snake.direction != (1, 0):
                        snake.direction = (-1, 0)
                    elif event.key == pygame.K_RIGHT and snake.direction != (-1, 0):
                        snake.direction = (1, 0)

        if not game_over:
            if not snake.move():
                game_over = True
                continue

            if snake.body[0] == food.pos:
                snake.grow = True
                score += 10
                food = Food()

        screen.fill(BLACK)
        snake.draw()
        food.draw()

        score_text = font.render(f"分数: {score}", True, WHITE)
        screen.blit(score_text, (10, 10))

        if game_over:
            game_over_text = font.render("游戏结束! 按空格重新开始", True, RED)
            screen.blit(game_over_text, (WIDTH // 2 - 170, HEIGHT // 2))

        pygame.display.flip()
        clock.tick(10)

    pygame.quit()

if __name__ == "__main__":
    main()
```

