        body { font-family: 'JetBrains Mono', 'Fira Code', monospace; background: #0d1117; color: #c9d1d9; min-height: 100vh; }
        .container { display: flex; height: 100vh; }
        .sidebar { width: 250px; background: #161b22; padding: 20px; border-right: 1px solid #30363d; overflow-y: auto; }
        .main { flex: 1; display: flex; flex-direction: column; }
        .header { padding: 15px 25px; border-bottom: 1px solid #30363d; display: flex; gap: 15px; align-items: center; }
        .header input { flex: 1; background: #0d1117; border: 1px solid #30363d; padding: 10px 15px; border-radius: 6px; color: #c9d1d9; }
        .header input:focus { outline: none; border-color: #58a6ff; }
        .header button { background: #238636; border: none; padding: 10px 20px; border-radius: 6px; color: white; cursor: pointer; }
        .editor { flex: 1; padding: 25px; display: none; }
        .editor.active { display: block; }
        .editor input, .editor textarea { width: 100%; background: #0d1117; border: 1px solid #30363d; padding: 12px; border-radius: 6px; color: #c9d1d9; margin-bottom: 15px; font-family: inherit; }
        .editor textarea { height: 60vh; resize: vertical; }
        .editor-actions { display: flex; gap: 10px; }
        .editor-actions button { padding: 10px 25px; border: none; border-radius: 6px; cursor: pointer; }
        .btn-save { background: #238636; color: white; }
        .btn-cancel { background: #21262d; color: #c9d1d9; }
        .notes-list { padding: 15px; }
        .note-item { background: #21262d; padding: 15px; border-radius: 6px; margin-bottom: 10px; cursor: pointer; border: 1px solid transparent; transition: all 0.2s; }
        .note-item:hover { border-color: #30363d; background: #30363d; }
        .note-item h3 { font-size: 14px; margin-bottom: 8px; color: #f0f6fc; }
        .note-item p { font-size: 12px; color: #8b949e; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
        .note-item .meta { display: flex; gap: 10px; margin-top: 8px; font-size: 11px; color: #6e7681; }
        .note-item .tag { background: #388bfd26; color: #58a6ff; padding: 2px 8px; border-radius: 12px; }
        .search-box { margin-bottom: 20px; }
        .search-box input { width: 100%; background: #0d1117; border: 1px solid #30363d; padding: 10px; border-radius: 6px; color: #c9d1d9; }
        .empty { text-align: center; padding: 40px; color: #6e7681; }
        .category-tabs { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 15px; }
        .category-tab { background: #21262d; padding: 6px 12px; border-radius: 6px; font-size: 12px; cursor: pointer; color: #8b949e; }
        .category-tab.active { background: #388bfd; color: white; }
    </style>
</head>
<body>
    <div class="container">
        <div class="sidebar">
            <h2 style="margin-bottom:20px;font-size:16px;">📚 笔记库</h2>
            <div class="category-tabs" id="categoryTabs"></div>
            <div class="notes-list" id="notesList"></div>
        </div>
        <div class="main">
            <div class="header">
                <input type="text" id="searchInput" placeholder="🔍 搜索笔记...">
                <button onclick="showEditor()">+ 新建</button>
            </div>
            <div class="notes-list" id="mainList"></div>
            <div class="editor" id="editor">
                <input type="text" id="noteTitle" placeholder="标题">
                <input type="text" id="noteTags" placeholder="标签（逗号分隔）">
                <textarea id="noteContent" placeholder="笔记内容...支持 Markdown"></textarea>
                <div class="editor-actions">
                    <button class="btn-save" onclick="saveNote()">💾 保存</button>
                    <button class="btn-cancel" onclick="hideEditor()">取消</button>
                    <button class="btn-cancel" onclick="deleteNote()" id="deleteBtn" style="margin-left:auto;display:none;">🗑️ 删除</button>
                </div>
            </div>
        </div>
    </div>
    <script>
        let currentNote = null;
        let currentCategory = '';

        async function loadNotes() {
            const search = document.getElementById('searchInput').value;
            let url = '/api/notes?search=' + search;
            if (currentCategory) url += '&category=' + currentCategory;
            const res = await fetch(url);
            const notes = await res.json();
            renderNotes(notes);
        }

        function renderNotes(notes) {
            const list = document.getElementById('mainList');
            if (notes.length === 0) {
                list.innerHTML = '<div class="empty">📭 暂无笔记，试试搜索或新建</div>';
                return;
            }
            list.innerHTML = notes.map(note => `
                <div class="note-item" onclick="editNote(${note.id})">
                    <h3>${note.title}</h3>
                    <p>${note.content.substring(0, 100)}...</p>
                    <div class="meta">
                        <span>${note.category}</span>
                        ${note.tags ? note.tags.split(',').map(t => `<span class="tag">${t.trim()}</span>`).join('') : ''}
                        <span>${new Date(note.updated_at).toLocaleDateString()}</span>
                    </div>
                </div>
            `).join('');
        }

